// Orquesta: Geocoding -> buildingInsights -> dataLayers -> Claude fallback
// Env: GOOGLE_API_KEY (req), ANTHROPIC_API_KEY (fallback)
// Input body: { address?, lat?, lon? }

const src = $input.first().json;
const body = src.body || src;
const inAddress = (body.address || '').toString().trim();
let lat = body.lat != null ? Number(body.lat) : null;
let lon = body.lon != null ? Number(body.lon) : null;
if (!inAddress && (lat == null || lon == null)) {
  return [{ json: { ok: false, reason: 'invalid_input', detail: 'address o lat/lon requeridos' } }];
}

// Acceso a env vars tolerante: el task runner de n8n puede denegar acceso ($env getter
// arroja TypeError cuando no está permitido). Devolvemos null en lugar de crashear.
const safeEnv = (k) => { try { return $env[k]; } catch (_) { return null; } };
const GKEY = safeEnv('GOOGLE_API_KEY');
const AKEY = safeEnv('ANTHROPIC_API_KEY');
if (!GKEY) {
  return [{ json: { ok: false, reason: 'missing_env', detail: 'GOOGLE_API_KEY no accesible desde el Code node. En Railway, definir GOOGLE_API_KEY en el servicio n8n y permitir acceso del task runner (NODE_FUNCTION_ALLOW_EXTERNAL / N8N_RUNNERS_TASK_RUNNER_ALLOWED_ENV).', address: inAddress, lat, lon } }];
}

// 1) Geocoding si no hay coords. Validación estricta + manejo de status Google.
//    NUNCA throws — siempre devuelve {ok:false, reason} para que el respond node lo
//    propague como JSON limpio en lugar de "Respuesta inválida" / 500.
//    Normaliza abreviaturas colombianas (Cra, Cl, Av, Tv, Dg, ª/º) antes de consultar.
let resolvedAddress = inAddress;

// Normaliza una dirección colombiana para Google Geocoding: expande abreviaturas comunes,
// quita ordinales (24ª → 24a), añade ", Colombia" si la dirección no menciona el país.
function normalizeColombianAddress(s) {
  if (!s) return s;
  let t = String(s).trim();
  // Indicadores ordinales: 24ª-44 → 24a-44; 12º → 12. Google los confunde con caracteres raros.
  t = t.replace(/[ªº°]/g, 'a').replace(/(\d)\s*a\b/gi, '$1a');
  // Abreviaturas: aplicar SOLO con word-boundary y respetando case-insensitive.
  // Reemplazos en orden de longitud descendente para evitar colisiones (Crr antes de Cr).
  const repl = [
    [/\b(carr?era|krr|crr|cra|cr)\.?\b/gi, 'Carrera'],
    [/\b(calle|cll|cl)\.?\b/gi,            'Calle'],
    [/\b(avenida|avda|avd|av)\.?\b/gi,    'Avenida'],
    [/\b(transversal|trv|tv)\.?\b/gi,     'Transversal'],
    [/\b(diagonal|dgn|dg)\.?\b/gi,         'Diagonal'],
    [/\b(autopista|aut|atp)\.?\b/gi,      'Autopista'],
    [/\b(manzana|mzn|mz)\.?\b/gi,          'Manzana'],
    [/\b(apartamento|apto|apt)\.?\b/gi,   'Apartamento'],
    [/\b(barrio|brr|bo)\.?\b/gi,           'Barrio'],
  ];
  for (const [re, val] of repl) t = t.replace(re, val);
  // Colapsar espacios.
  t = t.replace(/\s+/g, ' ').trim();
  // Asegurar país: si no menciona Colombia, añadir.
  if (!/colombia/i.test(t)) t = t + ', Colombia';
  return t;
}

async function geocodeOnce(query) {
  return this.helpers.httpRequest({
    method: 'GET',
    url: 'https://maps.googleapis.com/maps/api/geocode/json',
    qs: { address: query, key: GKEY, region: 'co', language: 'es' },
    json: true,
    returnFullResponse: true,
    ignoreHttpStatusErrors: true,
  });
}
const geocode = geocodeOnce.bind(this);

if (lat == null || lon == null) {
  // Heurística mínima: rechazar inputs imposibles de geocodificar (ej: "cra" sin número).
  if (inAddress.length < 8) {
    return [{ json: { ok: false, reason: 'invalid_input',
      detail: 'Ingresa una dirección más completa (calle/carrera + número + ciudad o departamento). Ej: "Carrera 7 # 32-16, Bogotá".',
      address: inAddress, lat: null, lon: null } }];
  }

  // Generar variantes a probar: normalizada → original → solo ciudad detectada.
  const normalized = normalizeColombianAddress(inAddress);
  const variants = [];
  if (normalized !== inAddress) variants.push(normalized);
  variants.push(inAddress);
  // Fallback ciudad: si el input contiene una ciudad reconocible al final, geocodificar solo eso.
  // Heurística: última palabra >3 chars sin números, asumiendo formato "<vía> <num> <ciudad>".
  const cityMatch = inAddress.match(/[A-Za-záéíóúñ]{4,}\s*$/i);
  if (cityMatch) {
    const cityOnly = cityMatch[0].trim() + ', Colombia';
    if (!variants.includes(cityOnly)) variants.push(cityOnly);
  }

  let geoResp = null;
  let geo = null;
  let usedQuery = null;
  for (const q of variants) {
    try {
      geoResp = await geocode(q);
    } catch (e) {
      return [{ json: { ok: false, reason: 'geocode_network',
        detail: 'No se pudo contactar Google Geocoding: ' + (e?.message || 'error desconocido'),
        address: inAddress, lat: null, lon: null } }];
    }
    if (geoResp.statusCode === 200 && geoResp.body && geoResp.body.status === 'OK' &&
        Array.isArray(geoResp.body.results) && geoResp.body.results.length > 0) {
      geo = geoResp.body;
      usedQuery = q;
      break;
    }
  }
  // Si ninguna variante respondió OK, devolver error específico según el último intento.
  if (!geo) {
    const last = geoResp || {};
    const body = last.body || {};
    if (last.statusCode && last.statusCode !== 200) {
      return [{ json: { ok: false, reason: 'geocode_http_' + last.statusCode,
        detail: 'Google Geocoding devolvió HTTP ' + last.statusCode + '. Verifica GOOGLE_API_KEY y que la API esté habilitada.',
        address: inAddress, lat: null, lon: null } }];
    }
    if (body.status === 'ZERO_RESULTS') {
      return [{ json: { ok: false, reason: 'no_geocode',
        detail: 'No se encontró la dirección. Probamos: ' + variants.join(' | ') + '. Sugerencias: revisa ortografía, agrega ciudad y departamento, o usa el formato "Carrera/Calle N #N-N, Ciudad".',
        address: inAddress, attempted: variants, lat: null, lon: null } }];
    }
    if (body.status && body.status !== 'OK') {
      return [{ json: { ok: false, reason: 'geocode_' + body.status.toLowerCase(),
        detail: body.error_message || ('Geocoding status: ' + body.status),
        address: inAddress, lat: null, lon: null } }];
    }
    return [{ json: { ok: false, reason: 'no_geocode',
      detail: 'No se encontró la dirección tras probar ' + variants.length + ' variantes.',
      address: inAddress, attempted: variants, lat: null, lon: null } }];
  }
  const top = geo.results[0];
  lat = top?.geometry?.location?.lat;
  lon = top?.geometry?.location?.lng;
  if (typeof lat !== 'number' || typeof lon !== 'number') {
    return [{ json: { ok: false, reason: 'geocode_no_coords',
      detail: 'Google Geocoding respondió pero sin coordenadas válidas.',
      address: inAddress, lat: null, lon: null } }];
  }
  resolvedAddress = top.formatted_address || usedQuery || inAddress;
}

// 2) Google Solar buildingInsights
let solar = null;
try {
  const sr = await this.helpers.httpRequest({
    method: 'GET',
    url: 'https://solar.googleapis.com/v1/buildingInsights:findClosest',
    qs: { 'location.latitude': lat, 'location.longitude': lon, requiredQuality: 'LOW', key: GKEY },
    json: true,
    returnFullResponse: true,
    ignoreHttpStatusErrors: true,
  });
  if (sr.statusCode === 200) solar = sr.body;
} catch {}

// 3) Google Solar dataLayers — GeoTIFF imagery URLs + shade/flux layers
let imagery = null;
try {
  const dl = await this.helpers.httpRequest({
    method: 'GET',
    url: 'https://solar.googleapis.com/v1/dataLayers:get',
    qs: {
      'location.latitude': lat,
      'location.longitude': lon,
      radiusMeters: 50,
      view: 'FULL_LAYERS',
      requiredQuality: 'LOW',
      key: GKEY,
    },
    json: true,
    returnFullResponse: true,
    ignoreHttpStatusErrors: true,
  });
  if (dl.statusCode === 200 && dl.body) {
    const d = dl.body;
    imagery = {
      dsmUrl: d.dsmUrl || null,
      rgbUrl: d.rgbUrl || null,
      maskUrl: d.maskUrl || null,
      annualFluxUrl: d.annualFluxUrl || null,
      monthlyFluxUrl: d.monthlyFluxUrl || null,
      hourlyShadeUrls: d.hourlyShadeUrls || [],
      imageryDate: d.imageryDate || null,
      imageryQuality: d.imageryQuality || null,
    };
  }
} catch {}

const sp = solar && solar.solarPotential;
if (sp) {
  const areaM2 = sp.maxArrayAreaMeters2 != null ? Number(sp.maxArrayAreaMeters2) : null;
  const maxPanels = sp.maxArrayPanelsCount != null ? Number(sp.maxArrayPanelsCount) : null;
  const sunshine = sp.maxSunshineHoursPerYear != null ? Number(sp.maxSunshineHoursPerYear) : null;
  let tiltDeg = null, azimuthDeg = null;
  const configs = sp.solarPanelConfigs || [];
  const best = configs.reduce((a, b) => (b.panelsCount > (a?.panelsCount || 0) ? b : a), null);
  const panels = sp.solarPanels || [];
  if (panels.length) {
    tiltDeg = panels[0].orientation === 'LANDSCAPE' ? 10 : 15;
  }
  const roofSegs = sp.roofSegmentStats || [];
  if (roofSegs.length) {
    let sumArea = 0, sumAz = 0, sumPitch = 0;
    for (const s of roofSegs) {
      const a = s.stats?.areaMeters2 || 0;
      sumArea += a; sumAz += (s.azimuthDegrees || 0) * a; sumPitch += (s.pitchDegrees || 0) * a;
    }
    if (sumArea > 0) {
      azimuthDeg = Math.round(sumAz / sumArea);
      tiltDeg = Math.round(sumPitch / sumArea);
    }
  }

  // Shade index: ratio avg(top-N panels) / max(panel energy)
  // 1.0 = no shade; 0.8 = 20% effective shading
  let shadeIndex = null, shadeSource = null;
  const energies = panels.map(p => Number(p.yearlyEnergyDcKwh || 0)).filter(v => v > 0);
  if (energies.length && best?.panelsCount) {
    const sorted = [...energies].sort((a, b) => b - a);
    const topN = sorted.slice(0, Math.min(best.panelsCount, sorted.length));
    const avgTop = topN.reduce((s, v) => s + v, 0) / topN.length;
    const maxE = sorted[0];
    if (maxE > 0) {
      shadeIndex = Math.max(0.1, Math.min(1, avgTop / maxE));
      shadeSource = 'google-solar-panels';
    }
  }

  const roofSegments = roofSegs.map(s => ({
    azimuthDegrees: s.azimuthDegrees,
    pitchDegrees: s.pitchDegrees,
    areaMeters2: s.stats?.areaMeters2 || 0,
    groundAreaMeters2: s.groundAreaMeters2 || null,
    sunshineHoursPerYear: s.stats?.sunshineQuantiles ? s.stats.sunshineQuantiles[4] : null,
  }));

  return [{ json: {
    lat, lon, address: resolvedAddress,
    areaM2, maxPanels, tiltDeg, azimuthDeg,
    sunshineHoursYear: sunshine,
    shadeIndex, shadeSource,
    roofSegments,
    imagery,
    source: 'google',
    confidence: 0.85,
    notes: best ? `config ${best.panelsCount} paneles${shadeIndex != null ? ` · sombra ${Math.round((1 - shadeIndex) * 100)}%` : ''}` : '',
  } }];
}

// 4) Fallback Claude — estimación por ubicación
if (!AKEY) {
  return [{ json: {
    lat, lon, address: resolvedAddress,
    areaM2: null, tiltDeg: 10, azimuthDeg: 180,
    shadeIndex: null, shadeSource: null, roofSegments: [], imagery: null,
    source: 'none', confidence: 0,
    notes: 'Solar API sin datos y ANTHROPIC_API_KEY no configurada',
  } }];
}
const prompt = `Eres un ingeniero solar FV en Colombia. Estima el área útil de techo en m² para paneles fotovoltaicos en esta ubicación residencial/comercial típica y un factor de sombreado aproximado.\n\nDirección: ${resolvedAddress}\nCoordenadas: ${lat}, ${lon}\n\nDevuelve SOLO JSON válido con esta forma exacta:\n{\"areaM2\": number, \"tiltDeg\": number, \"azimuthDeg\": number, \"shadeIndex\": number_0_to_1, \"confidence\": number_0_to_1, \"notes\": string}\n\nReglas:\n- Si no tienes contexto, asume vivienda promedio 40-80 m² de techo útil.\n- Azimuth 0=Norte, 90=Este, 180=Sur, 270=Oeste. En Colombia preferir ~180° con tilt 8-12°.\n- shadeIndex: 1.0 = sin sombra; 0.9-0.95 típico zona abierta; 0.8-0.85 con árboles o vecinos altos; < 0.8 sombra significativa. Estima conservador.`;

const claude = await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://api.anthropic.com/v1/messages',
  headers: { 'x-api-key': AKEY, 'anthropic-version': '2023-06-01', 'content-type': 'application/json' },
  body: { model: 'claude-haiku-4-5-20251001', max_tokens: 512, messages: [{ role: 'user', content: prompt }] },
  json: true,
});
const text = (claude.content || []).map(c => c.text || '').join('\n').trim();
const m = text.match(/\{[\s\S]*\}/);
if (!m) {
  return [{ json: { ok: false, reason: 'invalid_json', detail: 'Claude no devolvió JSON parseable', lat, lon, address: resolvedAddress, raw: text.slice(0, 500) } }];
}
let parsed;
try { parsed = JSON.parse(m[0]); } catch (e) {
  return [{ json: { ok: false, reason: 'invalid_json', detail: 'JSON inválido de Claude: ' + e.message, lat, lon, address: resolvedAddress, raw: m[0].slice(0, 500) } }];
}

return [{ json: {
  lat, lon, address: resolvedAddress,
  areaM2: parsed.areaM2 != null ? Number(parsed.areaM2) : null,
  tiltDeg: parsed.tiltDeg != null ? Number(parsed.tiltDeg) : 10,
  azimuthDeg: parsed.azimuthDeg != null ? Number(parsed.azimuthDeg) : 180,
  shadeIndex: parsed.shadeIndex != null ? Number(parsed.shadeIndex) : null,
  shadeSource: parsed.shadeIndex != null ? 'claude-estimate' : null,
  roofSegments: [], imagery: null,
  source: 'claude',
  confidence: parsed.confidence != null ? Number(parsed.confidence) : 0.4,
  notes: parsed.notes || '',
} }];
